VALUES
  ('social-worker-moex-02986', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '基因與遺傳對人類發展的影響不可忽視，以下那一項敘述是正確的？', '["隱性單一基因異常指的是，體內只要有一個異常的隱性基因就會發病", "紅綠色盲通常發生於男性身上，主要是因為Y染色體內有色盲的隱性基因", "人會因為基因的偏好而選擇自己的生活環境，同時也決定了環境對他的影響力", "人類與動物都有利他行為，唯一理由就是為了幫助他人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02987', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '如果案主自幼缺乏管教而經常出現攻擊別人的行為，從佛洛伊德的理論來看案主，下列那一項敘述是不 正確的？', '["案主的自我功能（ego function）不強，因為無法有效仲裁本我（id）與超我（superego）之間的衝突", "案主的自我理想(ego ideal)不強，因外在環境缺乏可供模仿的理想對象", "案主的本我功能（id）不強，因一向我行我素，慾望已經相當程度獲得滿足", "案主的超我功能（superego）不強，因生物的攻擊驅力所致"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02988', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '皮亞傑稱2~7歲兒童的認知發展為前運思期（preoperational stage），以下引號敘述何者不是此一階段之 特徵？', '["「能運用象徵，會虛構某些情節」，但某些大人會以為孩子愛說謊", "「能塗鴉，投射以代表某些人事物」，但某些大人會嗤之以鼻", "「能感受，認為萬物都有靈」，但某些大人認為這都是大人塑造的", "「具邏輯思考，喜歡問為什麼」，但某些大人並不以為然"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02989', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在行為學派的操作制約（operant conditioning）作法中，「給予所愛」是：', '["負向增強", "正向增強", "懲罰", "消除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02990', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '女權運動對女性生活處境的描述，以下何者不正確？', '["女性主義者關注女性遭受制度上不平等待遇之生活經驗", "女性主義者認為女性在婚姻中被壓迫主要是父權制度的結果", "女性主義者強調傳統性別角色社會化容易形成異性戀主流化", "女性主義者擔心女權運動會激起男性更進一步控制女性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02991', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在論證基因或環境對人類行為的影響程度時，下列何者受到基因決定的影響最多？', '["人格特質", "犯罪行為", "智力上的差異", "精神疾病"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02992', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項和新生兒的早產無關？', '["高齡產婦", "懷多胞胎", "幼兒體重不足", "第40週出生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02993', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在中年時期的成人，一方面必須照顧年老的父母親，一方面又必須面對養育兒女的艱辛，我們常稱之為：', '["三明治世代", "中年危機", "錯置的家庭主婦", "中斷生活"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
